noncompliant:
// Noncompliant: if-else if without final else clause
int processValue(int value) {
    if (value > 100) {
        return 1;
    } else if (value > 50) {
        return 2;
    }
    // Missing else clause - what happens if value <= 50?
}

compliant:
// Compliant: if-else if with final else clause
int processValue(int value) {
    if (value > 100) {
        return 1;
    } else if (value > 50) {
        return 2;
    } else {
        return 0;  // All cases handled
    }
}
